"""
MKT Christ Commentary — Proverbs chapters 22–24
Run: python3 scripts/zc-christ-proverbs-22-24.py

Key decisions in this range:
- Ch22:5 thorns/snares: connected to the thorn-curse of Gen 3:18 borne by Christ at the crown of thorns
- Ch23:10-11 goel (Redeemer): Christ as the strong Redeemer-Advocate (1 John 2:1; Heb 7:25)
- Ch23:23 'buy truth': John 14:6 (I am the truth) as fulfillment
- Ch24:3-4 wisdom-built house: Matt 7:24-27 and 1 Cor 3:11 (Christ as foundation)
- Ch24:16 righteous fall seven times and rise: shadow of the resurrection pattern
- Directness levels: 'direct' only for explicitly quoted verses; 'type/shadow/theme' for structural parallels
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

PROVERBS = {
  "22": {
    "1": "<p>A good name is to be chosen over great riches. The NT's ultimate statement on the incomparable name comes in Philippians 2:9: God exalted Christ and gave him 'the name that is above every name.' The 'good name' that wisdom calls more valuable than silver is a shadow of the name of Jesus, which is the highest name in creation. Matthew 12:42 declares that 'something greater than Solomon' stands here — the one whose name surpasses all wisdom's endorsements.</p>",
    "2": "<p>The rich and the poor have this in common: the LORD made them both — the theological foundation for economic solidarity. The NT applies this impartiality directly to the community of Christ: 'There is neither Jew nor Greek, slave nor free, male and female, for you are all one in Christ Jesus' (Gal 3:28). Peter declares that 'God shows no partiality' (Acts 10:34); the social barrier that divides rich and poor is dismantled in the community formed by the one who 'though he was rich, yet for your sake he became poor' (2 Cor 8:9).</p>",
    "3": "<p>The prudent person sees danger and takes cover; the naive go on and suffer. Discernment — perceiving the threat before it arrives — is a gift of wisdom. The NT applies this to the disciple's vigilance: 'Be sober-minded; be watchful. Your adversary the devil prowls around like a roaring lion, seeking someone to devour' (1 Pet 5:8). The cover that wisdom provides is the protection of abiding in Christ: 'Whoever abides in me and I in him, he it is that bears much fruit' (John 15:5).</p>",
    "4": "<p>The reward of humility and the fear of the LORD is riches, honor, and life — the paradox at the heart of wisdom: descent leads to ascent. This is the precise pattern of Christ's incarnation and exaltation: 'He humbled himself by becoming obedient to the point of death, even death on a cross. Therefore God has highly exalted him' (Phil 2:8-9). Proverbs 22:4 is the structural principle of which the crucifixion-resurrection is the supreme enactment. Humility before God leads to the life and honor that only God can give.</p>",
    "5": "<p>Thorns and snares are in the path of the perverse — the imagery of thorns is loaded with the curse of Genesis 3:18: 'thorns and thistles it shall bring forth for you.' The path of the perverse is the cursed ground of the fallen world. The christological fulfillment is the crown of thorns (Matt 27:29; Mark 15:17; John 19:2): Christ bore the thorns of the curse on his head, absorbing into himself the very emblem of the Fall. The snare in the way of the perverse is what Christ entered in order to dismantle: 'Christ redeemed us from the curse of the law by becoming a curse for us' (Gal 3:13).</p>",
    "6": "<p>Train a child in the way he should go; when he is old he will not depart from it — the wisdom of early formation. The NT picture of God's own child-formation runs through the incarnation: Luke records that 'Jesus increased in wisdom and in stature and in favor with God and man' (Luke 2:52), growing up in the formation of a devout Jewish family. More broadly, God trains his children through discipline (Heb 12:7-10): 'He disciplines us for our good, that we may share his holiness.' Formation by the Father is the pattern Christ both modeled and secured for his people.</p>",
    "7": "<p>The rich rule over the poor, and the borrower is slave to the lender — a social observation without explicit moral comment, but carrying implicit prophetic weight. The NT's reversal: 'For freedom Christ has set us free; stand firm therefore, and do not submit again to a yoke of slavery' (Gal 5:1). The debt-slavery metaphor runs through the NT's understanding of sin: we were debtors (Matt 6:12: forgive us our debts), and Christ paid what we could not. The economic observation of Proverbs 22:7 finds its theological extension in the liberation Christ accomplished.</p>",
    "8": "<p>Whoever sows injustice will reap trouble — the harvest principle. Paul cites the same structure in Galatians 6:7-8: 'Do not be deceived: God is not mocked, for whatever one sows, that will he also reap. For the one who sows to his own flesh will from the flesh reap corruption, but the one who sows to the Spirit will from the Spirit reap eternal life.' The sowing-reaping principle of Proverbs is made eschatological in Paul: the harvest of injustice is not merely social trouble but eternal corruption, reversed only by sowing to the Spirit of Christ.</p>",
    "9": "<p>A generous person will be blessed, for he shares his bread with the poor — the blessedness of generosity. Paul applies this in 2 Corinthians 9:6-9, quoting Psalm 112:9 but assuming the Proverbs framework: 'Whoever sows sparingly will also reap sparingly.' The christological foundation for generosity is the incarnation: 'You know the grace of our Lord Jesus Christ, that though he was rich, yet for your sake he became poor, so that you by his poverty might become rich' (2 Cor 8:9). Sharing bread with the poor is participating in the pattern of Christ.</p>",
    "10": "<p>Drive out the mocker and conflict goes with him — the purging of divisiveness from the community. The NT applies a similar principle to the church: 'A little leaven leavens the whole lump' (1 Cor 5:6); the one who causes divisions is to be avoided after a first and second warning (Tit 3:10). The mocker whose removal brings peace anticipates the eschatological removal of all that corrupts: 'in him there is no sin' (1 John 3:5), and his kingdom is the community from which all mockery is finally removed (Rev 21:27).</p>",
    "11": "<p>Whoever loves a pure heart and gracious speech will have the king as his friend — the connection between character and royal favor. The NT's application: 'Blessed are the pure in heart, for they shall see God' (Matt 5:8). Paul calls for speech that is 'gracious, seasoned with salt' (Col 4:6). The king as friend — the ultimate social endorsement — points to Christ's invitation: 'No longer do I call you servants... but I have called you friends' (John 15:15). Purity of heart and gracious speech are the character traits of the Christ-follower who is befriended by the King of kings.</p>",
    "12": "<p>The eyes of the LORD watch over knowledge and frustrate the words of the treacherous — divine omniscience as both protection and judgment. The NT: 'No creature is hidden from his sight, but all are naked and exposed to the eyes of him to whom we must give account' (Heb 4:13). Christ himself 'did not need anyone to testify about man, for he himself knew what was in man' (John 2:25). The watching eyes of the LORD that protect knowledge and expose treachery are the eyes of the risen Christ who walks among the lampstands (Rev 2:18: his eyes are like a flame of fire).</p>",
    "13": "<p>The sluggard says, 'There is a lion outside! I will be killed in the streets!' — fear as an excuse for inaction. The NT diagnoses the same pattern: the one-talent servant buried his talent 'because I was afraid' (Matt 25:25). The master's response — 'You wicked and slothful servant!' — identifies fear-based inaction as a form of wickedness. Christ calls his disciples to courage: 'Do not be afraid, little flock, for it is your Father's good pleasure to give you the kingdom' (Luke 12:32). The spirit of fear that manufactures excuses is countered by the Spirit of adoption that casts out fear (2 Tim 1:7).</p>",
    "14": "<p>The mouth of an adulterous woman is a deep pit — the covenant-infidelity that leads to death. The NT extends the spiritual dimension: James warns that 'friendship with the world is enmity with God' (Jas 4:4) and Paul uses the adultery metaphor for spiritual unfaithfulness (2 Cor 11:2-3). The pit of spiritual death is what Christ descended into and rose from; the deep pit of the adulteress is the structural opposite of the life that Christ offers: 'I came that they may have life and have it abundantly' (John 10:10).</p>",
    "15": "<p>Foolishness is bound up in the heart of a child, but the rod of discipline will drive it far — the reality of human moral default. The NT diagnosis is categorical: 'None is righteous, no, not one' (Rom 3:10); 'all have sinned and fall short of the glory of God' (Rom 3:23). The bound-up folly that requires discipline points to the need not merely for correction but for new birth: 'You must be born again' (John 3:7). The rod that drives out folly is the discipline of God through Christ's word and Spirit — or, in the deepest sense, the cross, which bears the wages of folly to bring freedom from it.</p>",
    "16": "<p>Oppressing the poor to enrich yourself, or giving gifts to the wealthy — both lead only to poverty — the double condemnation of social injustice. The Magnificat (Luke 1:52-53) declares the reversal: 'He has brought down the mighty from their thrones and exalted those of humble estate; he has filled the hungry with good things, and the rich he has sent empty away.' Both directions of injustice — exploitation and flattery of the powerful — are judged and inverted in the kingdom that Christ inaugurates.</p>",
    "17": "<p>Turn your ear and listen to the words of the wise — the opening of the 'Thirty Sayings' collection (22:17-24:22) with a direct appeal to the student. The appeal to listen is the NT's own call to discipleship: 'He who has ears to hear, let him hear' (Matt 13:9). Christ is the wisdom-teacher par excellence who says 'Come to me, all who labor and are heavy laden' (Matt 11:28) — the invitation to wisdom made personal and urgent.</p>",
    "18": "<p>It is good to keep them in your heart and have them ready on your lips — the internalization of wisdom as the basis for its expression. The Deuteronomic parallel (Deut 6:6-7: these words shall be on your heart; you shall teach them) is fulfilled in the new covenant: 'I will put my law within them, and I will write it on their hearts' (Jer 31:33). Christ is the mediator of this new covenant (Heb 9:15), making the internalization that Proverbs calls for possible through the Spirit who dwells in believers.</p>",
    "19": "<p>I am teaching you today — you specifically — so that your confidence may be in the LORD — wisdom addressed to the individual student. The personal address echoes throughout Jesus's ministry: 'Follow me' (Matt 4:19) — addressed to specific individuals. The confidence that comes from wisdom is not self-confidence but theocentric trust; Paul echoes this exactly: 'I have learned, in whatever situation I am, to be content' — confidence not from circumstances but from Christ who strengthens (Phil 4:11-13).</p>",
    "20": "<p>Have I not written down for you thirty excellent sayings of counsel and knowledge — the appeal to a written, authoritative source of wisdom. The NT's parallel: 'All Scripture is breathed out by God and profitable for teaching' (2 Tim 3:16). The written wisdom of Proverbs is part of the Scripture that Christ 'fulfills' (Matt 5:17) and that points to him (John 5:39: it is they that bear witness about me). The thirty sayings as authoritative counsel anticipates the authoritative teaching of Jesus who speaks 'as one who had authority, and not as their scribes' (Matt 7:29).</p>",
    "21": "<p>To teach you true and reliable words, so that you may give an accurate answer to those who sent you — the epistemic purpose of wisdom. The NT applies this to the disciple's witness: 'always being prepared to make a defense to anyone who asks you for a reason for the hope that is in you' (1 Pet 3:15). Jesus himself is 'the truth' (John 14:6), and those formed by wisdom about him are equipped to give 'accurate answers' — the verbal form of the truth they have received.</p>",
    "22": "<p>Do not rob the poor because they are poor or crush the afflicted at the city gate — the prophetic ethics of covenant protection for the vulnerable. The prophets amplified this: Isaiah 1:17 (seek justice, correct oppression, defend the fatherless). Jesus embodies and enacts it: 'Blessed are the poor in spirit' (Matt 5:3); 'the Spirit of the Lord is upon me... to proclaim good news to the poor' (Luke 4:18). Oppression of the poor is not merely social injustice but an offense against the one who identifies with the poor and marginalized.</p>",
    "23": "<p>For the LORD will take up their case and will plunder those who plundered them — the divine advocacy for the oppressed. The parable of the unjust judge (Luke 18:1-8) engages this promise directly: 'Will not God give justice to his elect, who cry to him day and night?' (Luke 18:7). Christ is the ultimate Advocate (1 John 2:1: we have an advocate with the Father, Jesus Christ the righteous) who takes up the case of the oppressed — and his advocacy is grounded in his own experience of being handed over to unjust power.</p>",
    "24": "<p>Do not befriend an angry man or associate with someone hot-tempered — the power of companionship to form character. The NT's positive form: 'Do not be deceived: Bad company ruins good morals' (1 Cor 15:33). Jesus's choice of companions is significant: he ate with tax collectors and sinners not to be formed by their character but to offer transformation. The disciples he called — 'Follow me' — were formed by his company, not by the company of the proud and violent. Companionship with Christ is the alternative wisdom offers.</p>",
    "25": "<p>Lest you learn his ways and set a trap for yourself — the insidious nature of moral contagion. The NT's 'be transformed by the renewing of your mind' (Rom 12:2) addresses the same reality from the positive direction: formation through companionship either corrupts or transforms depending on the company. The trap that angry company sets for the naive is the trap from which Christ frees — 'if the Son sets you free, you will be free indeed' (John 8:36).</p>",
    "26": "<p>Do not be one of those who shakes hands in a pledge or puts up security for loans — the wisdom of not taking on the debts of another impulsively. This is practical wisdom about financial exposure, but the christological irony is total: Christ is the one who did exactly what Proverbs warns against — he became surety for our debt, pledged himself for our obligations, and paid what we owed (Heb 7:22: Jesus has become the guarantor of a better covenant). What wisdom forbids as foolishness for a human becomes the gracious act of the mediator.</p>",
    "27": "<p>If you have nothing to pay with, why let him take away your bed from under you? — the realistic appraisal of the cost of surety. The wisdom principle stands: do not over-extend. But again the christological reversal: Christ was stripped (John 19:24: they divided his garments), left with nothing, so that we who had nothing might receive the wealth of his inheritance. He was impoverished so that we might be rich (2 Cor 8:9). What Proverbs warns the wise to avoid, Christ embraced voluntarily for our sake.</p>",
    "28": "<p>Do not move the ancient boundary stone that your ancestors put in place — the permanence of the covenant structure established by previous generations. The law as boundary is permanent: 'Do not think that I have come to abolish the Law or the Prophets; I have not come to abolish them but to fulfill them' (Matt 5:17). Christ does not remove the ancient markers; he fulfills them from within. The boundary stones of covenant ethics stand; Christ is the one who embodies and completes what they delimit.</p>",
    "29": "<p>Do you see a man skilled in his work? He will serve kings — not obscure people — the excellence and service principle. The faithful servant who is skilled in his work is given greater responsibility: 'Well done, good and faithful servant. You have been faithful over a little; I will set you over much' (Matt 25:21). The skilled servant who stands before kings anticipates the disciples who will judge the twelve tribes (Matt 19:28) and the saints who will reign with Christ (Rev 20:4). Excellence in service leads to royal commission — the pattern Christ establishes.</p>"
  },
  "23": {
    "1": "<p>When you sit down to eat with a ruler, give careful thought to what is before you — the meal as a place of discernment and formation. Table fellowship carries enormous weight in the NT: Jesus ate with sinners (Luke 15:1-2), shared the Last Supper with his disciples (Luke 22:14-20), and appeared at meals after the resurrection (Luke 24:30-35; John 21:12-13). The call to 'give careful thought to what is before you' has eucharistic resonance in Paul's warning: 'Let a person examine himself, then, and so eat of the bread and drink of the cup' (1 Cor 11:28). Every meal is a moment of discernment.</p>",
    "2": "<p>Put a knife to your throat if you have an unruly appetite — the radical language of self-denial in the face of dangerous desire. Jesus uses the same rhetoric of radical self-denial: 'If your right eye causes you to sin, tear it out and throw it away' (Matt 5:29); 'If anyone would come after me, let him deny himself and take up his cross' (Matt 16:24). The 'knife to the throat' is not literal self-harm but the drastic language of wisdom that takes the power of appetite seriously and requires radical counter-measures.</p>",
    "3": "<p>Do not crave his delicacies, for that food is deceptive — the appearance of benefit masking the reality of manipulation. Discernment about what appears beneficial but is actually deceptive runs through the NT: 'Even Satan disguises himself as an angel of light' (2 Cor 11:14); the false prophet who appears as a lamb but speaks like a dragon (Rev 13:11). The deceiving delicacy is the pattern of the temptation in Eden (Gen 3:6: good for food, a delight to the eyes) repeated in every enticing but corrupting offer.</p>",
    "4": "<p>Do not wear yourself out trying to get rich; have the wisdom to show restraint — the limit on wealth-acquisition as wisdom's discipline. Jesus says 'Do not lay up for yourselves treasures on earth, where moth and rust destroy and where thieves break in and steal, but lay up for yourselves treasures in heaven' (Matt 6:19-20). The wisdom to show restraint in the pursuit of wealth is the posture of those who have found the treasure of the kingdom (Matt 13:44) and are content with what they have (Heb 13:5).</p>",
    "5": "<p>Will you exhaust your eyes chasing what is not there? Riches sprout wings and fly away like an eagle — the vanishing nature of wealth. The parable of the rich fool (Luke 12:16-21) dramatizes this exactly: 'Soul, you have ample goods laid up for many years; relax, eat, drink, be merry. But God said to him, Fool! This night your soul is required of you.' The eagling away of wealth is the wisdom perspective on what death makes visible: only the investment that outlasts death has lasting value (Matt 6:20).</p>",
    "6": "<p>Do not eat the bread of a stingy man; do not covet his choice food — the discernment about false hospitality. The NT extends this: be wary of those who come offering apparent friendship but harbor contempt. Christ is the model of true generosity: 'I am the bread of life; whoever comes to me shall not hunger' (John 6:35). The bread of the stingy man leaves you hungry; the bread of Christ satisfies permanently. The call to discern bread sources is the wisdom preparation for recognizing the one who offers true nourishment.</p>",
    "7": "<p>He keeps a running count in his mind; he says 'Eat and drink,' but his heart is not with you — the exposure of false welcome. Jesus confronts exactly this in the Pharisees: outward hospitality concealing inward calculation. 'Beware of the leaven of the Pharisees, which is hypocrisy' (Luke 12:1). The contrast is Christ himself whose 'heart is with you' in the fullest sense: 'As the Father has loved me, so have I loved you' (John 15:9) — a welcome with nothing hidden, nothing calculated, nothing withheld.</p>",
    "8": "<p>You will vomit up the little you ate, and your pleasant words will have been wasted — the futility of participating in false fellowship. The wasted investment in false relationships and manipulative company is the wisdom warning about misplaced trust. The NT's alternative: 'Build one another up, just as you are doing' (1 Thess 5:11); fellowship grounded in Christ is the antidote to the empty returns of manipulative company. True community is formed around the one whose welcome is unconditional.</p>",
    "9": "<p>Do not speak in the hearing of a fool, for he will despise the wisdom of your words — the wisdom of audience discernment. Jesus gives the same guidance: 'Do not throw your pearls before pigs, lest they trample them underfoot and turn to attack you' (Matt 7:6). The selectivity about who receives wisdom is not elitism but realism — wisdom must be offered where it can take root. The parable of the soils (Matt 13:1-23) shows Christ himself practicing this discernment: the same seed is scattered widely, but only some ground receives it.</p>",
    "10": "<p>Do not move an ancient boundary stone; do not enter the fields of orphans — the covenant protection of the most vulnerable. The boundary-stone ethics of covenant community are combined here with the orphan-protection mandate (Deut 10:18: God executes justice for the fatherless). Jesus intensifies the stakes: whoever causes one of these little ones to stumble, it would be better for him to have a millstone hung around his neck (Matt 18:6). The protection of the vulnerable is not a secondary concern but a central marker of kingdom ethics.</p>",
    "11": "<p>For their Redeemer is strong; he will plead their case against you — the <em>gō'ēl</em> (kinsman-redeemer) of the fatherless. This is among the most directly Christological verses in Proverbs. Christ is identified as Redeemer (Heb: <em>gō'ēl</em>) throughout the NT: 'We have an advocate with the Father, Jesus Christ the righteous' (1 John 2:1). He is the strong Redeemer who pleads the case of those who cannot plead for themselves, 'always living to make intercession for them' (Heb 7:25). The anonymous Redeemer of Proverbs 23:11 is the pre-incarnate shadow of the Advocate who bears the name of Jesus.</p>",
    "12": "<p>Devote your heart to instruction and your ears to words of knowledge — the dual commitment of wisdom reception. The NT's 'faith comes from hearing, and hearing through the word of Christ' (Rom 10:17) identifies the ear as the instrument of saving reception. 'Devoting the heart' is the posture of the disciple who does not merely hear but integrates: 'Be doers of the word, and not hearers only, deceiving yourselves' (Jas 1:22). Christ both models total receptivity to the Father's word and is himself the word to which the heart must be devoted.</p>",
    "13": "<p>Do not withhold discipline from a child; if you strike him with the rod, he will not die — the necessity of formative discipline. Hebrews 12:5-6 quotes Proverbs 3:11-12 and extends the principle: 'Do not regard lightly the discipline of the Lord... for the Lord disciplines the one he loves.' Proverbs 23:13-14 is the parent's side of the same truth: withholding discipline is a failure of love. The formative rod that Proverbs commends is a shadow of God's fatherly discipline that the NT calls believers to receive without despising.</p>",
    "14": "<p>If you discipline him with the rod, you will save his life from death — discipline as an act of salvation. The connection between discipline and rescue from death is the wisdom principle. Christ's own formation — 'He learned obedience through what he suffered' (Heb 5:8) — is the supreme instance: the discipline of the cross saves many from death. The rod that saves the child from death is a shadow of the suffering that saves humanity; discipline is always, at its core, a redemptive act.</p>",
    "15": "<p>My son, if your heart is wise, then my heart will be glad as well — the joy of the wisdom-teacher in the student's formation. Jesus applies this to his own relationship with his disciples: 'These things I have spoken to you, that my joy may be in you, and that your joy may be full' (John 15:11). The Father's joy in the Son who learned wisdom (Luke 2:52) and the wisdom-teacher's joy in the growing student are the same pattern: God delights in the formation of his children, and Christ is the first and fullest recipient of that delight.</p>",
    "16": "<p>Yes, my inmost being will rejoice when your lips speak what is right — the wisdom-teacher's delight in the student's right speech. The connection between inner formation and right speech runs through the NT: 'Out of the abundance of the heart the mouth speaks' (Matt 12:34). What the lips speak is the measure of the heart's formation. Christ himself is the one in whose mouth 'no guile was found' (1 Pet 2:22; Isa 53:9) — the model of right speech that flows from a perfectly formed inner life.</p>",
    "17": "<p>Do not let your heart envy sinners, but live in the fear of the LORD all day long — the sustained posture of covenant trust over against envy. Paul reframes this: 'I have learned, in whatever situation I am, to be content' (Phil 4:11). The envy of the wicked who seem to prosper is addressed throughout Psalm 73, and its resolution is the same as Proverbs 23:17: the perspective of the sanctuary, where the end of the wicked is seen clearly. Contentment in the fear of the LORD is the posture of those who have set their hope on Christ rather than on the apparent success of the ungodly.</p>",
    "18": "<p>For surely there is a future, and your hope will not be cut off — the eschatological confidence that sustains the wisdom-walker. The NT intensifies and personalizes this hope: 'We rejoice in hope of the glory of God' (Rom 5:2); 'blessed be the God and Father of our Lord Jesus Christ! According to his great mercy, he has caused us to be born again to a living hope through the resurrection of Jesus Christ from the dead' (1 Pet 1:3). The 'future' that Proverbs promises is the resurrection — guaranteed by Christ's own rising, the firstfruits (1 Cor 15:20).</p>",
    "19": "<p>Listen, my son, and be wise; keep your heart on the right path — the simplest possible statement of the wisdom call. The heart that keeps to the right path is the single-minded heart of Matthew 6:22-23: 'The eye is the lamp of the body. So, if your eye is healthy, your whole body will be full of light.' Christ calls his disciples to the undivided heart that wisdom describes — the 'pure in heart' who will see God (Matt 5:8). Formation begins with listening; it produces a heart aligned with the way.</p>",
    "20": "<p>Do not be among those who drink too much wine or those who gorge themselves on meat — the warning against excess. The NT's positive form: 'Do not get drunk with wine... but be filled with the Spirit' (Eph 5:18). The drunkenness that Proverbs warns against is a counterfeit of the Spirit's fullness — both involve a kind of overwhelming, but one leads to waste and the other to worship. Christ was falsely accused of being a 'glutton and a drunkard' (Matt 11:19) for eating with sinners; the accusation reveals how completely he rejected the abstinence of the desert while also not practicing excess.</p>",
    "21": "<p>For the drunkard and the glutton will come to poverty, and drowsiness will clothe them with rags — the progressive impoverishment of excess. The NT's 'the desires of the flesh and the desires of the eyes and pride of life are not from the Father but are from the world. And the world is passing away along with its desires' (1 John 2:16-17) identifies the trajectory: desires that are not disciplined lead to the poverty and rags that Proverbs predicts. Christ offers the opposite: 'I counsel you to buy from me gold refined by fire, so that you may be rich... and white garments so that you may clothe yourself' (Rev 3:18).</p>",
    "22": "<p>Listen to your father who gave you life; do not despise your mother when she is old — the fifth commandment applied to the aging parent. Jesus reinforced this command against the Corban tradition (Mark 7:9-13: setting aside parental support in the name of religious obligation). He himself honored his mother even from the cross (John 19:26-27), commending her to the beloved disciple. The honoring of parents is not suspended by the kingdom but deepened: those who do the will of the Father are Christ's family (Matt 12:50), not a replacement for biological family but an extension of the covenant of honor.</p>",
    "23": "<p>Buy the truth and do not sell it — wisdom, instruction, and understanding as well — truth as the incomparably precious commodity. Jesus declares himself 'the truth' (John 14:6): to buy truth is, ultimately, to find Christ. Paul describes his own biographical enactment: 'I count everything as loss because of the surpassing worth of knowing Christ Jesus my Lord... I have suffered the loss of all things and count them as rubbish, in order that I may gain Christ' (Phil 3:8). The instruction not to sell truth is the call never to trade away one's hold on Christ for any lesser gain.</p>",
    "24": "<p>The father of a righteous child will greatly rejoice; the one who fathers a wise son will be glad — the joy of godly parenthood. The father who runs to meet the prodigal son (Luke 15:20) is the portrait of divine joy at human return to righteousness. More profoundly, the Father's declaration over Jesus — 'This is my beloved Son, with whom I am well pleased' (Matt 3:17) — is the climax of this verse's hope: a Father rejoicing in the perfect righteousness and wisdom of his Son. All fathers who rejoice in righteous children share, in miniature, the Father's delight in the Son.</p>",
    "25": "<p>Let your father and mother be glad; let the one who bore you rejoice — the ripple of the child's righteousness blessing the parents. Mary's Magnificat (Luke 1:46-55) is in part the expression of a mother's joy in a righteous Son. The rejoicing of Elizabeth (Luke 1:41-45) and Simeon (Luke 2:28-32) and Anna (Luke 2:38) at the birth of Jesus are the community's participation in the joy that a righteous child brings. Every instance of a child's wisdom bringing joy to parents is a participation in the pattern established at the birth of the one who is wisdom.</p>",
    "26": "<p>My son, give me your heart, and let your eyes keep watch over my ways — the central demand of wisdom: total commitment of the heart. The NT's form: 'You shall love the Lord your God with all your heart and with all your soul and with all your mind and with all your strength' (Mark 12:30). Jesus makes the giving of the heart the first and greatest commandment. Proverbs 23:26 is the wisdom form of what Jesus declares to be the summary of all divine demand: give me your whole heart. Wisdom calls for what only the gospel can produce — a heart genuinely given.</p>",
    "27": "<p>For a prostitute is a deep pit, and an immoral woman is a narrow well — the danger of covenant unfaithfulness. The pit and well imagery of spiritual death is inverted in John 4: at a well, Jesus offers 'living water' to the woman who has known covenant failure (John 4:10-14). The narrow well of Proverbs 23:27 becomes the location where Christ offers what no pit can give — water welling up to eternal life. The spiritual danger that the adulteress represents is the exact problem Christ addresses at the well: the thirst that false love cannot satisfy.</p>",
    "28": "<p>She lies in wait like a hunter and multiplies the unfaithful among men — the corrupting power of covenant-breaking desire. The NT: 'Each person is tempted when he is lured and enticed by his own desire. Then desire when it has conceived gives birth to sin, and sin when it is fully grown brings forth death' (Jas 1:14-15). The spreading of unfaithfulness is the pattern of every corrupting influence. Christ's counter-work is the converse: his faithfulness draws others into faithfulness, multiplying the covenant-keepers as the adulteress multiplies the faithless.</p>",
    "29": "<p>Who has grief? Who has anguish? Who has quarreling? Who has needless wounds? Who has bloodshot eyes? — the diagnostic questions about the fruit of drunkenness. The answer follows: those who linger over wine. The NT's diagnostic is broader: 'What causes quarrels and what causes fights among you? Is it not this, that your passions are at war within you?' (Jas 4:1). The grief and anguish that uncontrolled appetite produces are the outward signs of the inner warfare from which Christ promises liberation: 'Come to me, all who labor and are heavy laden, and I will give you rest' (Matt 11:28).</p>",
    "30": "<p>Those who linger over wine and go looking for spiced wine — the portrait of addictive pursuit. The NT addresses the same dynamic with a structural counter: 'Do not get drunk with wine, for that is debauchery, but be filled with the Spirit' (Eph 5:18). The seeking of spiced wine is redirected toward the seeking of the Spirit's filling. Christ transforms the water into wine at Cana (John 2:1-11), signaling that the era of abundance has arrived — but an abundance of the Spirit, not the wine that seduces.</p>",
    "31": "<p>Do not look at wine when it is red and sparkling in the cup — the seduction of the eye as the gateway to the will. The eye as the entry point for temptation is a consistent wisdom theme (Job 31:1: I have made a covenant with my eyes). Jesus: 'The eye is the lamp of the body. If your eye is healthy, your whole body will be full of light' (Matt 6:22). The sparkling wine that catches the eye represents every attractive thing that wisdom calls us to look away from, directing the gaze instead to what is truly worth seeing.</p>",
    "32": "<p>In the end it bites like a snake and stings like a viper — the deferred consequence of wine's seduction. The bite that comes after the pleasure mirrors the pattern of sin: 'The wages of sin is death' (Rom 6:23). Paul uses the snake metaphor for the same: 'the serpent deceived Eve by his cunning' (2 Cor 11:3). The viper-bite of Proverbs 23:32 connects to the serpent of Eden whose bite entered history and whose undoing comes through the seed of the woman (Gen 3:15) — Christ, who was struck but struck back, dying and rising.</p>",
    "33": "<p>Your eyes will see strange things; your heart will speak perverse things — the mental and moral distortion of drunkenness. The perverse heart that speaks perversion under the influence of wine is the picture of disordered desire. 'Out of the abundance of the heart the mouth speaks' (Matt 12:34): the perverse heart produces perverse speech. Christ's transformation reverses this: 'I will give you a new heart, and a new spirit I will put within you... I will put my Spirit within you' (Ezek 36:26-27). The new heart that speaks what is right is the gift of Christ through the Spirit.</p>",
    "34": "<p>You will be like one asleep in the middle of the sea, like one sprawled on top of the rigging — the vulnerability of the person overwhelmed by wine. Jonah slept in the ship's hold during the storm (Jon 1:5) while the sailors cried out to their gods; his sleep represented his flight from God. The ironic inversion: Jesus slept in the boat during the storm (Mark 4:38) not from the stupor of flight but from the peace of one who commands the sea. The drunken sailor asleep on the rigging contrasts with the sovereign Christ asleep in the stern.</p>",
    "35": "<p>'They beat me, but I felt no pain; they struck me, but I did not know it. When will I wake up so I can find another drink?' — the pathological insensibility and compulsion of addiction. The one who cannot feel the blows mirrors the hardened heart: 'Having become callous they have given themselves up to sensuality' (Eph 4:19). The compulsive 'when will I wake up' is the counter-image of the resurrection's waking: 'Awake, O sleeper, and arise from the dead, and Christ will shine on you' (Eph 5:14). The insensible drinker and the risen disciple represent the two ends of the spectrum — spiritual death and the waking of new life in Christ.</p>"
  },
  "24": {
    "1": "<p>Do not envy evil people or wish to be in their company — the prohibition against coveting the wicked's apparent advantage. The NT's 'do not be conformed to this world, but be transformed by the renewal of your mind' (Rom 12:2) addresses the same pull. Psalm 73 is the extended wisdom-meditation on this temptation: the poet nearly lost his footing until he entered the sanctuary and saw the end of the wicked. Christ is the sanctuary where the perspective is restored; in his light, the company of the wicked offers nothing worth envying.</p>",
    "2": "<p>For their heart plans violence, and their lips talk about causing trouble — the inner life of the wicked exposed. Jesus's forensic teaching: 'Out of the heart come evil thoughts, murder, adultery, sexual immorality, theft, false witness, slander' (Matt 15:19). The wicked whose hearts plan violence are what Christ diagnoses as the human condition without transformation. The new heart given in the new covenant (Ezek 36:26-27) replaces the heart that plans violence with the heart that loves; Christ is the mediator of that transformation.</p>",
    "3": "<p>By wisdom a house is built, and by understanding it is established — the parallel to Proverbs 3:19-20 (by wisdom the LORD founded the earth) applied to human construction. Jesus builds on this in Matthew 7:24-27: the wise builder who hears his words and does them builds on rock; the foolish one builds on sand. 1 Corinthians 3:10-11 makes the christological foundation explicit: 'no one can lay a foundation other than that which is laid, which is Jesus Christ.' Wisdom builds the house; Christ is the foundation the house is built on.</p>",
    "4": "<p>Through knowledge the rooms are filled with all kinds of precious and pleasant treasures — the interior abundance of the wisdom-built house. The NT: 'in him all the fullness of God was pleased to dwell' (Col 1:19); 'the whole fullness of deity dwells bodily' in Christ (Col 2:9). The house filled with precious treasures through knowledge is a type of the fullness that dwells in Christ — and by extension, the fullness given to those who are 'in him who is the head of all rule and authority' (Col 2:10). The knowledge that fills the rooms is ultimately the knowledge of Christ.</p>",
    "5": "<p>A wise man is strong, and a man of knowledge grows in might — wisdom as true power. The NT's paradox: 'the word of the cross is folly to those who are perishing, but to us who are being saved it is the power of God' (1 Cor 1:18). The strength that wisdom gives is not the strength of armies but the strength of God: 'not by might, nor by power, but by my Spirit, says the LORD of hosts' (Zech 4:6). Christ is 'the power of God and the wisdom of God' (1 Cor 1:24) — the one in whom true might and true wisdom are identical.</p>",
    "6": "<p>For by wise guidance you can wage war, and victory depends on having many advisers — the wisdom of counsel in conflict. The NT: 'the weapons of our warfare are not of the flesh but have divine power to destroy strongholds' (2 Cor 10:4). The wise guidance Proverbs commends is the Spirit who leads into all truth (John 16:13): 'the Counselor... will teach you all things' (John 14:26). Victory in spiritual warfare depends on the counsel of the Spirit of Christ, the many-counseled wisdom of God disclosed in the one who bore all the names of Isaiah 9:6: Wonderful Counselor.</p>",
    "7": "<p>Wisdom is beyond a fool's reach; he has nothing to say at the city gate — the inaccessibility of wisdom to the spiritually unformed. The NT parallel: 'The natural person does not accept the things of the Spirit of God, for they are folly to him, and he is not able to understand them because they are spiritually discerned' (1 Cor 2:14). The wisdom that the fool cannot reach is precisely what Paul declares hidden in Christ: 'wisdom among the mature, a secret and hidden wisdom of God' (1 Cor 2:6-7) — accessible only to those who have the Spirit who searches even the depths of God.</p>",
    "8": "<p>Whoever schemes to do evil will be known as a troublemaker — the social exposure of the schemer. The hypocrisy that schemes while appearing upright is what Jesus confronts in the religious leaders: 'Woe to you, scribes and Pharisees, hypocrites!' (Matt 23:27). The troublemaker who is finally exposed mirrors the judgment of the last day: 'nothing is covered up that will not be revealed' (Luke 12:2). Christ both exposes evil schemes in his earthly ministry and will fully reveal them at the judgment (1 Cor 4:5: the Lord will bring to light the things now hidden in darkness).</p>",
    "9": "<p>The intention behind foolish schemes is sin, and the mocker is detestable to everyone — sin beginning in intention, not merely in action. Jesus extends this exactly: You have heard it was said, you shall not commit adultery, but I say to you that everyone who looks at a woman with lustful intent has already committed adultery in his heart (Matt 5:27-28). The wisdom principle that intention is already sin is radicalized by Christ, who traces sin to its root in the heart and calls for transformation at that level — not merely behavioral control but new birth.</p>",
    "10": "<p>If you falter in times of trouble, how small is your strength! — the test of trouble as the measure of wisdom's depth. Hebrews 12:1-3 directs this endurance precisely to Christ: 'let us run with endurance the race that is set before us, looking to Jesus, the founder and perfecter of our faith, who for the joy that was set before him endured the cross.' The strength that does not falter in trouble is not stoic resilience but Christ-anchored faith; the one who endured the cross gives endurance to those who look to him.</p>",
    "11": "<p>Rescue those being taken away to death; hold back those stumbling toward slaughter — the active advocacy for the condemned. James's 'save a soul from death' (Jas 5:20) and the parable of the Good Samaritan (Luke 10:25-37) engage this call. Christ himself embodies it at the supreme level: he came to rescue those 'being taken away to death' — enslaved to sin, destined for condemnation — and his cross is the rescue operation. The call to intervene for the condemned is a call to participate in the rescue pattern that defines Christ's own mission.</p>",
    "12": "<p>If you say, 'We did not know this,' does not he who weighs the heart perceive it? — the impossibility of pleading ignorance before the God who knows. Hebrews 4:13: 'No creature is hidden from his sight, but all are naked and exposed to the eyes of him to whom we must give account.' Jesus: 'I tell you, on the day of judgment people will give account for every careless word they speak' (Matt 12:36). The God who weighs hearts and repays according to deeds (Prov 24:12b) is the God whose omniscience is disclosed fully in Christ, who 'knew what was in man' (John 2:25).</p>",
    "13": "<p>My son, eat honey because it is good, and the honeycomb that is sweet to your taste — wisdom tasted as pleasure. Psalm 19:10 uses the same image: God's law is 'sweeter also than honey and drippings of the honeycomb.' Psalm 119:103: 'How sweet are your words to my taste, sweeter than honey to my mouth!' The sweetness of wisdom's word is a theme that culminates in Revelation 10:9-10 where John eats the scroll and it is sweet in the mouth but bitter in the stomach — wisdom received is sweet; wisdom enacted in judgment is bitter. Christ is the word that is both sweet and costly.</p>",
    "14": "<p>So is wisdom to your soul; when you find it, there is a future, and your hope will not be cut off — wisdom as the ground of eschatological hope. The NT's hope is grounded in a person: 'Christ in you, the hope of glory' (Col 1:27). Finding wisdom means finding Christ — and finding Christ means the future is secured. 'We have this as a sure and steadfast anchor of the soul, a hope that enters into the inner place behind the curtain, where Jesus has gone as a forerunner on our behalf' (Heb 6:19-20). The uncut hope of Proverbs 24:14 is the anchor of Hebrews 6.</p>",
    "15": "<p>Do not lie in wait against the home of the righteous; do not raid his dwelling place — the prohibition against targeting the righteous. The wicked who target the righteous are the structural opponents of Christ's people: 'If the world hates you, know that it has hated me before it hated you' (John 15:18). Christ himself was the righteous one targeted by ambush — the councils and plots against him (Matt 26:3-5). The prohibition in Proverbs is violated against Christ; its violation becomes the occasion for the resurrection that vindicates the righteous sufferer.</p>",
    "16": "<p>For a righteous person falls seven times and gets up again, but the wicked are brought down by calamity — the resilience of the righteous through repeated falls. Seven falls and seven risings is the wisdom way of saying: the righteous are never finally defeated. The NT: 'We are afflicted in every way, but not crushed; perplexed, but not driven to despair; persecuted, but not forsaken; struck down, but not destroyed' (2 Cor 4:8-9). Christ's own fall into death is the ultimate instance — and his rising the ultimate getting up again. The pattern of the righteous person who falls and rises is the shape of Easter applied to all who are in Christ.</p>",
    "17": "<p>Do not gloat when your enemy falls, and do not let your heart be glad when he stumbles — the restraint of enemy-love, even in victory. Jesus makes this explicit: 'Love your enemies and pray for those who persecute you' (Matt 5:44). The restraint Proverbs calls for becomes in Christ the positive command to active love of enemies — not merely not gloating but pursuing their good. Christ embodies this from the cross: 'Father, forgive them, for they know not what they do' (Luke 23:34). No gloating in victory; only love for those who stumble.</p>",
    "18": "<p>Lest the LORD see it and be displeased, and he turn his anger away from your enemy — the surprising logic: gloating over an enemy's downfall can move God to spare the enemy. This is the hidden mercy in God's justice: his displeasure at cruelty can become the basis for the adversary's rescue. The NT extends this: 'Vengeance is mine, I will repay, says the Lord' (Rom 12:19) — the removal of vengeance from human hands is itself a form of grace toward the enemy. God's justice is trustworthy; human gloating is not, and it can become a reversal of God's purposes.</p>",
    "19": "<p>Do not fret because of evildoers or be envious of the wicked — the peace of those who have eschatological perspective. Psalm 37 extends this over 40 verses: the prosperity of the wicked is temporary; the inheritance of the righteous is permanent. The NT's transformation: 'Do not be anxious about anything, but in everything by prayer and supplication with thanksgiving let your requests be made known to God. And the peace of God, which surpasses all understanding, will guard your hearts and your minds in Christ Jesus' (Phil 4:6-7). The peace that prevents fretting is the peace of Christ.</p>",
    "20": "<p>For the evil person has no future reward; the lamp of the wicked will be snuffed out — the eschatological finality of the wicked's end. Jesus uses the same lamp imagery: 'the foolish virgins' lamps went out (Matt 25:8); 'there will be weeping and gnashing of teeth' (Matt 25:30). The lamp snuffed out is the definitive end; the lamp that burns is the life of the faithful disciple (Matt 5:16: let your light shine before others). Christ is 'the light of the world' (John 8:12) — the one whose lamp cannot be snuffed out, the source from which all true lamps are lit.</p>",
    "21": "<p>My son, fear the LORD and the king, and do not associate with those who seek to change — the call to proper submission to authority. The NT: 'Be subject for the Lord's sake to every human institution, whether it be to the emperor as supreme or to governors as sent by him' (1 Pet 2:13-14); 'Let every person be subject to the governing authorities. For there is no authority except from God' (Rom 13:1). Christ himself submitted to Roman authority even in his condemnation (John 19:11: you would have no authority over me at all unless it had been given you from above), modeling the submission he calls his people toward.</p>",
    "22": "<p>For their disaster will come suddenly, and who knows what destruction may come from them both? — the unpredictable judgment that falls on the rebellious. The sudden disaster is a consistent eschatological warning: while people are saying peace and security, sudden destruction will come upon them (1 Thess 5:3). The warning to avoid those who seek to change — to resist established order — is the wisdom observation that revolutionary destabilization reaps its own judgment. The kingdom of Christ does not come through violent overthrow but through the patient faithfulness that submitted even to the cross.</p>",
    "23": "<p>These also are sayings of the wise: showing partiality in judgment is not right — the opening of a supplementary wisdom collection. The impartiality of God as judge is a cornerstone of both OT and NT theology: 'God shows no partiality' (Acts 10:34; Rom 2:11; 1 Pet 1:17). Christ himself demonstrated this impartiality — eating with Pharisees and sinners alike, healing both Jews and Gentiles, dying for the ungodly of every tribe and tongue. The judge who shows no partiality is the same God who gives 'every good gift' impartially (Jas 1:17).</p>",
    "24": "<p>Whoever tells the guilty, 'You are innocent,' will be cursed by peoples and condemned by nations — the cost of false acquittal. Pilate is the supreme historical instance: he declared Jesus innocent (John 18:38: I find no guilt in him) and then condemned him anyway — the double falseness of calling the innocent guilty in deed while calling him innocent in word. The perversion of justice that Proverbs condemns is carried to its extreme in the trial of Christ, where the truly innocent was condemned and the guilty were released (Barabbas, Mark 15:6-15). The judgment of nations against false judges is ultimately the judgment at which Christ is vindicated.</p>",
    "25": "<p>But those who rebuke the wicked will find delight, and a generous blessing will come upon them — the vindication of the honest rebuke. Nathan's rebuke of David (2 Sam 12:1-7) is the OT model; John the Baptist's rebuke of Herod (Mark 6:18) and Jesus's rebukes of the religious leaders (Matt 23) are the NT expressions. The blessing on honest rebukers comes at cost — John was beheaded; Jesus was crucified — but the delight and blessing that Proverbs promises are eschatological: 'Blessed are you when others revile you and persecute you and utter all kinds of evil against you falsely on my account. Rejoice and be glad, for your reward is great in heaven' (Matt 5:11-12).</p>",
    "26": "<p>Whoever gives an honest answer is like a kiss on the lips — truthful speech as intimate gift. The NT: 'Speaking the truth in love, we are to grow up in every way into him who is the head, into Christ' (Eph 4:15). The honest answer that is 'like a kiss' combines intimacy and truth — the combination that Christ embodies: 'full of grace and truth' (John 1:14). The kiss of Judas was the inversion — intimacy used as betrayal. Christ's truth-speaking was always also an act of love toward the hearer, even when confrontational.</p>",
    "27": "<p>Prepare your outdoor work and get your fields ready; after that, build your house — the right ordering of priorities. Jesus uses counting-the-cost language that parallels this: 'Which of you, desiring to build a tower, does not first sit down and count the cost?' (Luke 14:28). The ordering of outdoor work before household building is the wisdom that puts foundation before superstructure. Christ calls his disciples to count the cost of discipleship before committing — not to discourage but to ensure the house is built on the right foundation in the right order.</p>",
    "28": "<p>Do not testify against your neighbor without cause; do not deceive with your lips — the covenant prohibition of false witness (the ninth commandment). Jesus addresses false witness in his trial (Matt 26:59-60: the chief priests sought false testimony), and his own example — 'When he was reviled, he did not revile in return' (1 Pet 2:23) — is the model of refusing to return false accusation with false accusation. The neighbor protected from false witness finds its highest expression in Christ's refusal to fabricate charges even against those who fabricated charges against him.</p>",
    "29": "<p>Do not say, I will do to him what he did to me — the prohibition against personal revenge. Paul cites the divine prerogative: never avenge yourselves, but leave it to the wrath of God, for it is written, vengeance is mine, I will repay, says the Lord (Rom 12:19). Jesus extends this to the positive: love your enemies, do good to those who hate you (Luke 6:27). The renunciation of revenge is not passive resignation but the active trust that God's justice is sufficient — and Christ's cross is the definitive act in which God dealt with sin without human revenge being needed.</p>",
    "30": "<p>I passed by the field of a lazy man and the vineyard of a man who lacked sense — the wisdom observation that begins the extended sluggard passage. The observational mode here — the wisdom teacher drawing a lesson from a concrete scene — anticipates Jesus's parabolic method: drawing eternal lessons from vineyards, fields, and everyday sights. The field of the sluggard that the teacher passes by is the same genre as the vineyard parables of Jesus (Mark 12:1-12; Matt 21:33-46), where neglected responsibility has consequences.</p>",
    "31": "<p>It was all overgrown with thorns; the ground was covered with nettles, and the stone wall was in ruins — the landscape of neglect. The ruined vineyard of Isaiah 5:1-7 is the prophetic escalation of this image: the beloved's vineyard that yielded wild grapes, interpreted as Israel's failure to produce justice. Jesus applies the vineyard parable to the leaders who failed to tend God's vineyard and will have it taken from them (Matt 21:43). The overgrown field of Proverbs 24:31 is the seed from which the prophetic vineyard parables of judgment grow.</p>",
    "32": "<p>I saw it and took it to heart; I looked and received instruction — wisdom's habit of learning from what is observed. The capacity to receive instruction from the created world is part of the wisdom tradition: 'Go to the ant, you sluggard; consider her ways, and be wise' (Prov 6:6). Jesus teaches in parables drawn from birds of the air, lilies of the field, sowers, and vineyards precisely because creation is legible to those who have eyes to see (Matt 13:13-17). The wisdom habit of learning from what is seen is the posture of the disciple who perceives the kingdom in what Jesus shows.</p>",
    "33": "<p>A little sleep, a little slumber, a little folding of the hands to rest — the incremental self-deception of the lazy person. The same verse appears in Proverbs 6:10; its repetition underlines its diagnostic importance. The NT's urgency: 'Besides this you know the time, that the hour has come for you to wake from sleep. For salvation is nearer to us now than when we first believed' (Rom 13:11). The folding of the hands in the face of eschatological urgency is precisely the failure that the NT warns against; Proverbs provides the wisdom diagnosis, and Paul provides the eschatological motivation to rise.</p>",
    "34": "<p>Then poverty will come on you like a wanderer, and your need like an armed man — the sudden arrival of the consequences of sloth. The armed intruder of poverty arriving suddenly mirrors the eschatological warnings: 'The Son of Man is coming at an hour you do not expect' (Matt 24:44); 'the day of the Lord will come like a thief in the night' (1 Thess 5:2). The sudden arrival of poverty for the sluggard is the wisdom anticipation of the sudden arrival of eschatological accountability. The call to faithful labor — watching, working, waiting — is the NT's application of Proverbs' sloth-warning to the disciples who await the Master's return.</p>"
  }
}

def main():
    existing = load_comm('mkt-christ', 'proverbs')
    merge_comm(existing, PROVERBS)
    save_comm('mkt-christ', 'proverbs', existing)

    import json as _json
    il = _json.load(open(str(ROOT / 'data' / 'interlinear' / 'proverbs.json')))
    out = existing
    for ch in [22, 23, 24]:
        ck = str(ch)
        missing = set(il.get(ck, {}).keys()) - set(out.get(ck, {}).keys())
        print(f'  ch{ch}: {"complete" if not missing else "MISSING " + str(sorted(missing, key=int))}')

if __name__ == '__main__':
    main()
